package com.example.dataproc.grpc;

import io.grpc.ManagedChannel;
import io.grpc.netty.NettyChannelBuilder;
import io.grpc.stub.StreamObserver;
import io.netty.channel.ChannelOption;

import java.io.Closeable;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.Iterator;
import java.util.Map;
import java.util.UUID;
import java.util.concurrent.CountDownLatch;
import java.util.concurrent.TimeUnit;

import com.google.protobuf.ByteString;

public final class DataTransferClient implements Closeable {
    private final ManagedChannel channel;
    private final DataTransferServiceGrpc.DataTransferServiceStub stub;
    private final DataTransferServiceGrpc.DataTransferServiceBlockingStub blockingStub;

    public DataTransferClient(String host, int port) {
        this.channel = NettyChannelBuilder.forAddress(host, port)
                .usePlaintext()
                .maxInboundMessageSize(Integer.MAX_VALUE)
                .maxInboundMetadataSize(Integer.MAX_VALUE)
                .withOption(ChannelOption.SO_RCVBUF, 1024 * 1024)
                .withOption(ChannelOption.SO_SNDBUF, 1024 * 1024)
                .build();
        this.stub = DataTransferServiceGrpc.newStub(channel);
        this.blockingStub = DataTransferServiceGrpc.newBlockingStub(channel);
    }

    public UploadSummary uploadFile(Path file, String remoteFileName, Map<String, String> metadata) throws Exception {
        String uploadId = UUID.randomUUID().toString();
        CountDownLatch done = new CountDownLatch(1);
        final UploadSummary[] result = new UploadSummary[1];
        final Throwable[] error = new Throwable[1];

        StreamObserver<UploadSummary> respObs = new StreamObserver<>() {
            @Override
            public void onNext(UploadSummary value) {
                result[0] = value;
            }

            @Override
            public void onError(Throwable t) {
                error[0] = t;
                done.countDown();
            }

            @Override
            public void onCompleted() {
                done.countDown();
            }
        };

        StreamObserver<UploadChunk> reqObs = stub.upload(respObs);

        long offset = 0L;
        int chunkSize = 256 * 1024;
        byte[] buf = new byte[chunkSize];

        try (var in = Files.newInputStream(file)) {
            int n;
            while ((n = in.read(buf)) >= 0) {
                UploadChunk.Builder b = UploadChunk.newBuilder()
                        .setUploadId(uploadId)
                        .setFileName(remoteFileName)
                        .setOffset(offset)
                        .setData(ByteString.copyFrom(buf, 0, n))
                        .setLast(false);
                if (metadata != null) b.putAllMetadata(metadata);
                reqObs.onNext(b.build());
                offset += n;
            }

            UploadChunk.Builder last = UploadChunk.newBuilder()
                    .setUploadId(uploadId)
                    .setFileName(remoteFileName)
                    .setOffset(offset)
                    .setData(ByteString.EMPTY)
                    .setLast(true);
            if (metadata != null) last.putAllMetadata(metadata);
            reqObs.onNext(last.build());
            reqObs.onCompleted();
        } catch (Throwable t) {
            reqObs.onError(t);
            throw t;
        }

        if (!done.await(5, TimeUnit.MINUTES)) {
            throw new RuntimeException("upload timeout");
        }
        if (error[0] != null) {
            throw new RuntimeException(error[0]);
        }
        return result[0];
    }

    public void bidiEcho(Iterator<TransferMessage> messages, StreamObserver<TransferMessage> responses) {
        StreamObserver<TransferMessage> req = stub.transfer(responses);
        while (messages.hasNext()) req.onNext(messages.next());
        req.onCompleted();
    }

    public Iterator<DownloadChunk> download(String fileName, long offset, long limit, Map<String, String> metadata) {
        DownloadRequest.Builder b = DownloadRequest.newBuilder()
                .setFileName(fileName)
                .setOffset(offset)
                .setLimit(limit);
        if (metadata != null) b.putAllMetadata(metadata);
        return blockingStub.download(b.build());
    }

    @Override
    public void close() throws IOException {
        channel.shutdown();
        try {
            channel.awaitTermination(5, TimeUnit.SECONDS);
        } catch (InterruptedException ignored) {
        }
    }
}